import { Server } from 'socket.io';
import crypto from 'crypto';

const SHARD_COUNT = 16;

function shardOf(userId: string): number {
  return crypto.createHash('md5').update(userId).digest().readUInt32BE(0) % SHARD_COUNT;
}

export function shardedRoomName(baseRoom: string, shard: number): string { return `${baseRoom}:s${shard}`; }

export class ShardedRoomBroadcaster {
  constructor(private readonly io: Server) {}

  joinUser(socketId: string, baseRoom: string, userId: string): void {
    const socket = this.io.sockets.sockets.get(socketId);
    if (!socket) return;
    socket.join(shardedRoomName(baseRoom, shardOf(userId)));
  }

  broadcast(baseRoom: string, event: string, payload: unknown): void {
    for (let i = 0; i < SHARD_COUNT; i++) {
      this.io.to(shardedRoomName(baseRoom, i)).emit(event, payload);
    }
  }

  broadcastToUser(baseRoom: string, userId: string, event: string, payload: unknown): void {
    this.io.to(shardedRoomName(baseRoom, shardOf(userId))).emit(event, payload);
  }
}

import type { Socket } from 'socket.io-client';

interface OutboxEntry { id: string; event: string; payload: unknown; createdAt: number; }

export class SocketOutbox {
  private queue: OutboxEntry[] = [];
  private inFlight: Set<string> = new Set();

  constructor(private readonly socket: Socket, private readonly ackTimeoutMs = 5000) {
    socket.on('connect', () => { void this.flush(); });
  }

  enqueue(event: string, payload: unknown): string {
    const id = crypto.randomUUID();
    this.queue.push({ id, event, payload, createdAt: Date.now() });
    if (this.socket.connected) void this.flush();
    return id;
  }

  private async flush(): Promise<void> {
    while (this.queue.length > 0) {
      const entry = this.queue[0];
      if (this.inFlight.has(entry.id)) return;
      this.inFlight.add(entry.id);
      const ok = await this.send(entry);
      this.inFlight.delete(entry.id);
      if (!ok) return;
      this.queue.shift();
    }
  }

  private send(entry: OutboxEntry): Promise<boolean> {
    return new Promise<boolean>((resolve) => {
      const timer = setTimeout(() => resolve(false), this.ackTimeoutMs);
      this.socket.emit(entry.event, { ...(entry.payload as object), __outboxId: entry.id }, (ack: { ok?: boolean } | undefined) => {
        clearTimeout(timer);
        resolve(ack?.ok === true);
      });
    });
  }
}

import type { Redis } from 'ioredis';
import { Server, Socket } from 'socket.io';

const TTL_SEC = 60;
const HEARTBEAT_MS = 20_000;

export class PresenceTracker {
  constructor(private readonly redis: Redis, private readonly io: Server) {}

  private key(userId: string): string { return `presence:${userId}`; }

  async markOnline(userId: string, socketId: string): Promise<void> {
    await this.redis.set(this.key(userId), socketId, 'EX', TTL_SEC);
    this.io.emit('presence:online', { userId });
  }

  async heartbeat(userId: string): Promise<void> { await this.redis.expire(this.key(userId), TTL_SEC); }

  async markOffline(userId: string, socketId: string): Promise<void> {
    const current = await this.redis.get(this.key(userId));
    if (current !== socketId) return;
    await this.redis.del(this.key(userId));
    this.io.emit('presence:offline', { userId });
  }

  async isOnline(userId: string): Promise<boolean> { return (await this.redis.exists(this.key(userId))) === 1; }
}

export function attachPresence(io: Server, tracker: PresenceTracker): void {
  io.on('connection', async (socket: Socket) => {
    const userId = (socket.data as { userId?: string }).userId;
    if (!userId) return;
    await tracker.markOnline(userId, socket.id);
    const interval = setInterval(() => { void tracker.heartbeat(userId); }, HEARTBEAT_MS);
    socket.on('disconnect', async () => { clearInterval(interval); await tracker.markOffline(userId, socket.id); });
  });
}

import cluster from 'cluster';
import os from 'os';
import { createServer } from 'http';
import { Server } from 'socket.io';
import { setupMaster, setupWorker } from '@socket.io/sticky';
import { setupPrimary, createAdapter } from '@socket.io/cluster-adapter';

export function startClusteredServer(port: number, attachApp: (io: Server) => void): void {
  if (cluster.isPrimary) {
    const httpServer = createServer();
    setupMaster(httpServer, { loadBalancingMethod: 'least-connection' });
    setupPrimary();
    httpServer.listen(port);
    const cpus = os.cpus().length;
    for (let i = 0; i < cpus; i++) cluster.fork();
    cluster.on('exit', () => cluster.fork());
    return;
  }

  const httpServer = createServer();
  const io = new Server(httpServer);
  io.adapter(createAdapter());
  setupWorker(io);
  attachApp(io);
}

import { Server, Namespace } from 'socket.io';

export interface ChatRoomHooks {
  onCreate(roomId: string, nsp: Namespace): void;
  onClose(roomId: string): void;
}

export function mountDynamicChatRooms(io: Server, hooks: ChatRoomHooks): void {
  const seen = new Set<string>();
  const chatNs = io.of(/^\/chat\/[a-z0-9-]{3,32}$/);

  chatNs.use((socket, next) => {
    if (!(socket.data as { userId?: string }).userId) return next(new Error('UNAUTHENTICATED'));
    next();
  });

  chatNs.on('connection', (socket) => {
    const nsp = socket.nsp;
    const roomId = nsp.name.slice('/chat/'.length);
    if (!seen.has(roomId)) { seen.add(roomId); hooks.onCreate(roomId, nsp); }

    socket.on('disconnect', async () => {
      const sockets = await nsp.fetchSockets();
      if (sockets.length === 0) { seen.delete(roomId); hooks.onClose(roomId); }
    });
  });
}

import { io, Socket } from 'socket.io-client';

let socket: Socket | null = null;

export function getSocket(): Socket {
  if (socket) return socket;
  socket = io(import.meta.env.VITE_WS_URL, {
    withCredentials: true,
    autoConnect: false,
    reconnection: true,
  });
  socket.connect();
  return socket;
}

export function disposeSocket(): void {
  if (!socket) return;
  socket.removeAllListeners();
  socket.disconnect();
  socket = null;
}

import { useEffect, useRef } from 'react';

export function useSharedSocket(): Socket {
  const socketRef = useRef<Socket | null>(null);
  if (!socketRef.current) socketRef.current = getSocket();
  useEffect(() => () => {}, []);
  return socketRef.current;
}

import crypto from 'crypto';

export interface PkcePair { codeVerifier: string; codeChallenge: string; codeChallengeMethod: 'S256'; }

export function generatePkce(): PkcePair {
  const codeVerifier = crypto.randomBytes(32).toString('base64url');
  const codeChallenge = crypto.createHash('sha256').update(codeVerifier).digest('base64url');
  return { codeVerifier, codeChallenge, codeChallengeMethod: 'S256' };
}

export function buildAuthorizeUrl(opts: { authorizeEndpoint: string; clientId: string; redirectUri: string; scope: string[]; pkce: PkcePair; state: string }): string {
  const params = new URLSearchParams({
    client_id: opts.clientId,
    redirect_uri: opts.redirectUri,
    response_type: 'code',
    scope: opts.scope.join(' '),
    code_challenge: opts.pkce.codeChallenge,
    code_challenge_method: 'S256',
    state: opts.state,
  });
  return `${opts.authorizeEndpoint}?${params.toString()}`;
}

export interface TokenResponse { access_token: string; refresh_token?: string; token_type: 'Bearer'; expires_in: number; }

export async function exchangeCode(opts: { tokenEndpoint: string; clientId: string; code: string; redirectUri: string; codeVerifier: string }): Promise<TokenResponse> {
  const body = new URLSearchParams({
    grant_type: 'authorization_code',
    client_id: opts.clientId,
    code: opts.code,
    redirect_uri: opts.redirectUri,
    code_verifier: opts.codeVerifier,
  });
  const res = await fetch(opts.tokenEndpoint, { method: 'POST', headers: { 'Content-Type': 'application/x-www-form-urlencoded' }, body });
  if (!res.ok) throw new Error(`TOKEN_EXCHANGE_FAILED_${res.status}`);
  return res.json() as Promise<TokenResponse>;
}

import { Request, Response } from 'express';
import type { Session, SessionData } from 'express-session';

declare module 'express-session' { interface SessionData { userId?: string; csrfToken?: string; loggedInAt?: number; } }

function regenerateSession(req: Request): Promise<void> {
  return new Promise((resolve, reject) => { req.session.regenerate((err) => (err ? reject(err) : resolve())); });
}

function destroySession(req: Request): Promise<void> {
  return new Promise((resolve, reject) => { req.session.destroy((err) => (err ? reject(err) : resolve())); });
}

export async function postLogin(req: Request, res: Response, userId: string): Promise<void> {
  const preserved = { csrfToken: req.session.csrfToken };
  await regenerateSession(req);
  req.session.userId = userId;
  req.session.csrfToken = preserved.csrfToken;
  req.session.loggedInAt = Date.now();
  res.json({ ok: true });
}

export async function postLogout(req: Request, res: Response): Promise<void> {
  await destroySession(req);
  res.clearCookie('connect.sid');
  res.json({ ok: true });
}

