export function pickAllowed<T extends Record<string, unknown>>(input: T, allowed: ReadonlyArray<keyof T>): Partial<T> {
  const out: Partial<T> = {};
  for (const key of allowed) if (key in input && input[key] !== undefined) out[key] = input[key];
  return out;
}

export async function patchMe(req: Request, res: Response): Promise<void> {
  const parsed = UpdateProfileDto.safeParse(req.body);
  if (!parsed.success) { res.status(422).json({ errors: parsed.error.flatten() }); return; }
  const userId = (req as Request & { userId: string }).userId;
  const updated = await UserModel.findByIdAndUpdate(userId, { $set: parsed.data }, { new: true, lean: true }).select('-passwordHash');
  res.json({ user: updated });
}

import jwt, { JwtHeader, SigningKeyCallback } from 'jsonwebtoken';
import crypto from 'crypto';

export interface KeyEntry { kid: string; privateKey: string; publicKey: string; createdAt: number; }

export class JwtKeyset {
  private keys = new Map<string, KeyEntry>();
  private activeKid: string | null = null;

  addKey(entry: KeyEntry, active = true): void {
    this.keys.set(entry.kid, entry);
    if (active) this.activeKid = entry.kid;
  }

  retireKey(kid: string): void { this.keys.delete(kid); if (this.activeKid === kid) this.activeKid = null; }

  sign(payload: object, expiresIn = '15m'): string {
    if (!this.activeKid) throw new Error('NO_ACTIVE_KEY');
    const entry = this.keys.get(this.activeKid)!;
    return jwt.sign(payload, entry.privateKey, { algorithm: 'RS256', keyid: entry.kid, expiresIn });
  }

  verify(token: string): unknown {
    return jwt.verify(token, (header: JwtHeader, cb: SigningKeyCallback) => {
      if (!header.kid) return cb(new Error('MISSING_KID'));
      const entry = this.keys.get(header.kid);
      if (!entry) return cb(new Error('UNKNOWN_KID'));
      cb(null, entry.publicKey);
    }, { algorithms: ['RS256'] });
  }
}

export function generateRsaKeypair(): { privateKey: string; publicKey: string; kid: string } {
  const { privateKey, publicKey } = crypto.generateKeyPairSync('rsa', { modulusLength: 2048, privateKeyEncoding: { type: 'pkcs8', format: 'pem' }, publicKeyEncoding: { type: 'spki', format: 'pem' } });
  const kid = crypto.createHash('sha256').update(publicKey).digest('hex').slice(0, 16);
  return { privateKey, publicKey, kid };
}

import { Request, Response, NextFunction } from 'express';
import net from 'net';

interface CidrRange { network: bigint; mask: bigint; family: 4 | 6; }

function parseCidr(cidr: string): CidrRange {
  const [ip, bitsStr] = cidr.split('/');
  const bits = Number(bitsStr);
  const family = net.isIP(ip);
  if (family !== 4 && family !== 6) throw new Error('INVALID_IP');
  if (family === 4 && (bits < 0 || bits > 32)) throw new Error('INVALID_BITS');
  if (family === 6 && (bits < 0 || bits > 128)) throw new Error('INVALID_BITS');
  const ipBig = ipToBigInt(ip);
  const totalBits = family === 4 ? 32 : 128;
  const mask = ((1n << BigInt(bits)) - 1n) << BigInt(totalBits - bits);
  return { network: ipBig & mask, mask, family: family as 4 | 6 };
}

function ipToBigInt(ip: string): bigint {
  if (net.isIP(ip) === 4) {
    return ip.split('.').reduce((acc, oct) => (acc << 8n) | BigInt(Number(oct)), 0n);
  }
  const parts = ip.split(':');
  return parts.reduce((acc, p) => (acc << 16n) | BigInt(parseInt(p || '0', 16)), 0n);
}

function inRange(ip: string, range: CidrRange): boolean {
  if (net.isIP(ip) !== range.family) return false;
  return (ipToBigInt(ip) & range.mask) === range.network;
}

export function ipAllowlist(cidrs: ReadonlyArray<string>) {
  const ranges = cidrs.map(parseCidr);
  return (req: Request, res: Response, next: NextFunction): void => {
    const ip = req.ip;
    if (!ip || !ranges.some((r) => inRange(ip, r))) { res.status(403).json({ error: 'IP_NOT_ALLOWED' }); return; }
    next();
  };
}

import express from 'express';

export function configureBodyParsers(app: express.Express): void {
  app.use(express.json({ limit: '100kb', strict: true }));
  app.use(express.urlencoded({ extended: false, limit: '100kb', parameterLimit: 50 }));

  app.use((err: unknown, _req: express.Request, res: express.Response, next: express.NextFunction) => {
    if (err && typeof err === 'object' && 'type' in err && err.type === 'entity.too.large') {
      res.status(413).json({ error: 'PAYLOAD_TOO_LARGE' });
      return;
    }
    next(err);
  });
}

import cors from 'cors';
import express from 'express';

export function configureCors(app: express.Express, allowedOrigins: ReadonlyArray<string>): void {
  app.use(cors({
    origin: (origin, cb) => {
      if (!origin || allowedOrigins.includes(origin)) return cb(null, true);
      cb(new Error('CORS_NOT_ALLOWED'));
    },
    credentials: true,
    methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE'],
    allowedHeaders: ['Content-Type', 'Authorization', 'X-CSRF-Token', 'X-Request-Id', 'X-Idempotency-Key'],
    exposedHeaders: ['X-Request-Id', 'X-RateLimit-Remaining', 'X-RateLimit-Reset'],
    maxAge: 600,
  }));
  app.options('*', cors());
}

import { useSyncExternalStore } from 'react';

interface CounterStore { getState: () => number; subscribe: (l: () => void) => () => void; increment: () => void; }

export function createCounterStore(initial = 0): CounterStore {
  let state = initial;
  const listeners = new Set<() => void>();
  return {
    getState: () => state,
    subscribe: (l) => { listeners.add(l); return () => { listeners.delete(l); }; },
    increment: () => { state++; listeners.forEach((l) => l()); },
  };
}

import { createContext, useContext, useRef, ReactNode } from 'react';
const Ctx = createContext<CounterStore | null>(null);

export function CounterProvider({ children }: { children: ReactNode }): JSX.Element {
  const ref = useRef<CounterStore | null>(null);
  if (!ref.current) ref.current = createCounterStore();
  return <Ctx.Provider value={ref.current}>{children}</Ctx.Provider>;
}

export function useCounter(): number {
  const store = useContext(Ctx);
  if (!store) throw new Error('No CounterProvider');
  return useSyncExternalStore(store.subscribe, store.getState, store.getState);
}

export function useIncrement(): () => void {
  const store = useContext(Ctx);
  if (!store) throw new Error('No CounterProvider');
  return store.increment;
}

import { useReducer } from 'react';

export interface CartItem { sku: string; qty: number; }
export interface CartState { items: CartItem[]; lastModifiedAt: number; }

export type CartAction =
  | { type: 'ADD'; item: CartItem; at: number }
  | { type: 'REMOVE'; sku: string; at: number }
  | { type: 'CLEAR'; at: number };

export function cartReducer(state: CartState, action: CartAction): CartState {
  switch (action.type) {
    case 'ADD': {
      const existing = state.items.find((i) => i.sku === action.item.sku);
      const items = existing
        ? state.items.map((i) => (i.sku === action.item.sku ? { ...i, qty: i.qty + action.item.qty } : i))
        : [...state.items, action.item];
      return { items, lastModifiedAt: action.at };
    }
    case 'REMOVE':
      return { items: state.items.filter((i) => i.sku !== action.sku), lastModifiedAt: action.at };
    case 'CLEAR':
      return { items: [], lastModifiedAt: action.at };
  }
}

export function useCart() {
  const [state, dispatch] = useReducer(cartReducer, { items: [], lastModifiedAt: 0 });
  const add = (item: CartItem): void => dispatch({ type: 'ADD', item, at: Date.now() });
  const remove = (sku: string): void => dispatch({ type: 'REMOVE', sku, at: Date.now() });
  const clear = (): void => dispatch({ type: 'CLEAR', at: Date.now() });
  return { state, add, remove, clear };
}

interface Resource<T> { read(): T; }

export function createResource<T>(fetcher: () => Promise<T>): Resource<T> {
  let status: 'pending' | 'success' | 'error' = 'pending';
  let result: T;
  let error: unknown;
  const promise = fetcher().then(
    (r) => { status = 'success'; result = r; },
    (e) => { status = 'error'; error = e; },
  );
  return {
    read(): T {
      if (status === 'pending') throw promise;
      if (status === 'error') throw error;
      return result;
    },
  };
}

const cache = new Map<string, Resource<unknown>>();
export function getOrCreateResource<T>(key: string, fetcher: () => Promise<T>): Resource<T> {
  let resource = cache.get(key) as Resource<T> | undefined;
  if (!resource) { resource = createResource(fetcher); cache.set(key, resource); }
  return resource;
}

export function invalidateResource(key: string): void { cache.delete(key); }

