import { useState, useCallback } from 'react';

export function useMeasure(): { ref: (node: HTMLElement | null) => void; size: { width: number; height: number } | null } {
  const [size, setSize] = useState<{ width: number; height: number } | null>(null);

  const ref = useCallback((node: HTMLElement | null) => {
    if (!node) { setSize(null); return; }
    const measure = (): void => {
      const rect = node.getBoundingClientRect();
      setSize({ width: rect.width, height: rect.height });
    };
    measure();
    const ro = new ResizeObserver(measure);
    ro.observe(node);
    (node as HTMLElement & { __ro?: ResizeObserver }).__ro = ro;
  }, []);

  return { ref, size };
}

// caveat: cleanup of the ResizeObserver requires a different ref callback pattern in React 19; 
// using callback ref with cleanup return:
export function useMeasureV19(): { ref: (node: HTMLElement | null) => (() => void) | void; size: { width: number; height: number } | null } {
  const [size, setSize] = useState<{ width: number; height: number } | null>(null);
  const ref = useCallback((node: HTMLElement | null) => {
    if (!node) return;
    const measure = (): void => {
      const rect = node.getBoundingClientRect();
      setSize({ width: rect.width, height: rect.height });
    };
    measure();
    const ro = new ResizeObserver(measure);
    ro.observe(node);
    return () => ro.disconnect();
  }, []);
  return { ref, size };
}

