import { useEffect, useState } from 'react';

export function useWindowSize(): { width: number; height: number } {
  const [size, setSize] = useState(() => ({ width: window.innerWidth, height: window.innerHeight }));

  useEffect(() => {
    const handler = (): void => setSize({ width: window.innerWidth, height: window.innerHeight });
    window.addEventListener('resize', handler);
    handler();
    return () => window.removeEventListener('resize', handler);
  }, []);

  return size;
}

import { Object3D, Box3, Vector3 } from 'three';

export interface NormalizeOptions { targetSize: number; groundY?: number; }

export function normalizeModel(root: Object3D, opts: NormalizeOptions): void {
  const box = new Box3().setFromObject(root);
  const size = new Vector3();
  box.getSize(size);
  const maxDim = Math.max(size.x, size.y, size.z);
  if (maxDim === 0) return;

  const scale = opts.targetSize / maxDim;
  root.scale.setScalar(scale);

  const scaledBox = new Box3().setFromObject(root);
  const center = new Vector3();
  scaledBox.getCenter(center);

  root.position.x -= center.x;
  root.position.z -= center.z;
  if (opts.groundY !== undefined) root.position.y -= scaledBox.min.y - opts.groundY;
  else root.position.y -= center.y;
}

import { MeshStandardMaterial, Shader, MeshStandardMaterialParameters } from 'three';

export interface DissolveUniforms { uThreshold: { value: number }; uEdgeWidth: { value: number }; uEdgeColor: { value: [number, number, number] }; }

export function createDissolveMaterial(base: MeshStandardMaterialParameters): { material: MeshStandardMaterial; uniforms: DissolveUniforms } {
  const material = new MeshStandardMaterial(base);
  const uniforms: DissolveUniforms = {
    uThreshold: { value: 0 },
    uEdgeWidth: { value: 0.05 },
    uEdgeColor: { value: [1.0, 0.4, 0.0] },
  };

  material.onBeforeCompile = (shader: Shader): void => {
    shader.uniforms.uThreshold = uniforms.uThreshold;
    shader.uniforms.uEdgeWidth = uniforms.uEdgeWidth;
    shader.uniforms.uEdgeColor = { value: uniforms.uEdgeColor.value };

    shader.vertexShader = `varying vec3 vWorldPos;\n` + shader.vertexShader.replace('#include <worldpos_vertex>', '#include <worldpos_vertex>\nvWorldPos = worldPosition.xyz;');

    shader.fragmentShader = `uniform float uThreshold;\nuniform float uEdgeWidth;\nuniform vec3 uEdgeColor;\nvarying vec3 vWorldPos;\nfloat hash(vec3 p){ p=fract(p*0.3183099+0.1); p*=17.0; return fract(p.x*p.y*p.z*(p.x+p.y+p.z));}\n` + shader.fragmentShader;
    shader.fragmentShader = shader.fragmentShader.replace(
      '#include <dithering_fragment>',
      `float n = hash(floor(vWorldPos * 8.0));\nif (n < uThreshold) discard;\nif (n < uThreshold + uEdgeWidth) gl_FragColor.rgb = mix(gl_FragColor.rgb, uEdgeColor, 1.0 - (n - uThreshold) / uEdgeWidth);\n#include <dithering_fragment>`
    );
  };

  return { material, uniforms };
}

import { Mesh, BufferGeometry, Group, LOD, Object3D, Sphere, Box3 } from 'three';

export function ensureFrustumCullingReady(root: Object3D): void {
  root.traverse((node) => {
    if (!(node instanceof Mesh)) return;
    node.frustumCulled = true;
    const geo = node.geometry as BufferGeometry;
    if (!geo.boundingSphere) geo.computeBoundingSphere();
    if (!geo.boundingBox) geo.computeBoundingBox();
  });
}

export interface LodLevel { mesh: Mesh; distance: number; }

export function createLod(levels: ReadonlyArray<LodLevel>): LOD {
  const lod = new LOD();
  for (const { mesh, distance } of levels) lod.addLevel(mesh, distance);
  lod.autoUpdate = true;
  return lod;
}

import { Canvas, useThree, useFrame } from '@react-three/fiber';
import { OrbitControls } from '@react-three/drei';
import { useEffect } from 'react';

function InvalidateOnControls(): null {
  const invalidate = useThree((s) => s.invalidate);
  const controls = useThree((s) => s.controls) as unknown as { addEventListener?: (e: string, h: () => void) => void; removeEventListener?: (e: string, h: () => void) => void } | null;
  useEffect(() => {
    if (!controls?.addEventListener) return;
    const onChange = (): void => invalidate();
    controls.addEventListener('change', onChange);
    return () => controls.removeEventListener?.('change', onChange);
  }, [controls, invalidate]);
  return null;
}

