import { Router, Request, Response, NextFunction, RequestHandler } from 'express';

export function safeHandler(handler: RequestHandler): RequestHandler {
  return (req: Request, res: Response, next: NextFunction): void => {
    try {
      const out = handler(req, res, next);
      if (out && typeof (out as Promise<unknown>).catch === 'function') {
        (out as Promise<unknown>).catch(next);
      }
    } catch (err) { next(err); }
  };
}

export function safeRouter(): Router {
  const router = Router();
  const wrap = <K extends 'get' | 'post' | 'put' | 'patch' | 'delete'>(method: K): void => {
    const original = router[method].bind(router);
    (router as unknown as Record<string, unknown>)[method] = (path: string, ...handlers: RequestHandler[]) => original(path, ...handlers.map(safeHandler));
  };
  (['get', 'post', 'put', 'patch', 'delete'] as const).forEach(wrap);
  return router;
}

export class JobTimeoutError extends Error { readonly code = 'JOB_TIMEOUT' as const; constructor(public readonly jobId: string, public readonly timeoutMs: number) { super(`Job ${jobId} timed out after ${timeoutMs}ms`); } }

export interface JobContext { signal: AbortSignal; jobId: string; }

export async function runJobWithTimeout<T>(jobId: string, timeoutMs: number, work: (ctx: JobContext) => Promise<T>): Promise<T> {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  const ctx: JobContext = { signal: controller.signal, jobId };

  const timeoutPromise = new Promise<never>((_, reject) => {
    controller.signal.addEventListener('abort', () => reject(new JobTimeoutError(jobId, timeoutMs)), { once: true });
  });

  try {
    return await Promise.race([work(ctx), timeoutPromise]);
  } finally {
    clearTimeout(timer);
  }
}

import { Request, Response, NextFunction, ErrorRequestHandler } from 'express';
import { getRequestId } from './request-context';

export interface ErrorReporter { report(error: Error, context: Record<string, unknown>): void; }

const REDACT_HEADERS = new Set(['authorization', 'cookie', 'x-csrf-token']);

function safeHeaders(headers: Record<string, string | string[] | undefined>): Record<string, string> {
  const out: Record<string, string> = {};
  for (const [k, v] of Object.entries(headers)) {
    if (v === undefined) continue;
    out[k] = REDACT_HEADERS.has(k.toLowerCase()) ? '[REDACTED]' : Array.isArray(v) ? v.join(', ') : v;
  }
  return out;
}

export function contextualErrorMiddleware(reporter: ErrorReporter): ErrorRequestHandler {
  return (err: unknown, req: Request, res: Response, _next: NextFunction): void => {
    const error = err instanceof Error ? err : new Error(String(err));
    const userId = (req as Request & { userId?: string }).userId;
    reporter.report(error, {
      requestId: getRequestId(),
      userId,
      method: req.method,
      path: req.path,
      query: req.query,
      headers: safeHeaders(req.headers as Record<string, string | string[] | undefined>),
    });
    if (res.headersSent) return;
    res.status(500).json({ error: { code: 'INTERNAL', message: 'An unexpected error occurred', requestId: getRequestId() } });
  };
}

export interface NotificationResult { delivered: boolean; reference?: string; }
export interface NotificationRequest { recipient: string; subject: string; body: string; }

export interface Notifier {
  readonly channel: string;
  canDeliver(req: NotificationRequest): boolean;
  send(req: NotificationRequest): Promise<NotificationResult>;
}

export class EmailNotifier implements Notifier {
  readonly channel = 'email';
  canDeliver(req: NotificationRequest): boolean { return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(req.recipient); }
  async send(req: NotificationRequest): Promise<NotificationResult> {
    if (!this.canDeliver(req)) return { delivered: false };
    return { delivered: true, reference: `mail:${Date.now()}` };
  }
}

export class SmsNotifier implements Notifier {
  readonly channel = 'sms';
  canDeliver(req: NotificationRequest): boolean { return /^\+\d{8,15}$/.test(req.recipient); }
  async send(req: NotificationRequest): Promise<NotificationResult> {
    if (!this.canDeliver(req)) return { delivered: false };
    return { delivered: true, reference: `sms:${Date.now()}` };
  }
}

export async function dispatch(notifiers: ReadonlyArray<Notifier>, req: NotificationRequest): Promise<NotificationResult[]> {
  return Promise.all(notifiers.filter((n) => n.canDeliver(req)).map((n) => n.send(req)));
}

