// pool.ts
import { Worker } from 'worker_threads';
import path from 'path';

interface Task<I, O> { input: I; resolve: (out: O) => void; reject: (err: Error) => void; }

export class WorkerPool<I, O> {
  private workers: Worker[] = [];
  private idle: Worker[] = [];
  private queue: Task<I, O>[] = [];

  constructor(workerScript: string, size: number) {
    for (let i = 0; i < size; i++) {
      const w = new Worker(path.resolve(workerScript));
      this.workers.push(w);
      this.idle.push(w);
    }
  }

  run(input: I): Promise<O> {
    return new Promise<O>((resolve, reject) => {
      this.queue.push({ input, resolve, reject });
      this.dispatch();
    });
  }

  private dispatch(): void {
    while (this.idle.length > 0 && this.queue.length > 0) {
      const worker = this.idle.shift()!;
      const task = this.queue.shift()!;
      const onMessage = (msg: { ok: true; value: O } | { ok: false; error: string }): void => {
        worker.off('message', onMessage);
        worker.off('error', onError);
        this.idle.push(worker);
        if (msg.ok) task.resolve(msg.value); else task.reject(new Error(msg.error));
        this.dispatch();
      };
      const onError = (err: Error): void => { worker.off('message', onMessage); task.reject(err); };
      worker.once('message', onMessage);
      worker.once('error', onError);
      worker.postMessage(task.input);
    }
  }

  async terminate(): Promise<void> { await Promise.all(this.workers.map((w) => w.terminate())); }
}

