import { ChangeStream, ResumeToken } from 'mongodb';
import { OrderModel } from './order.model';
import type { Server } from 'socket.io';

export class OrderChangeFanout {
  private stream: ChangeStream | null = null;
  private resumeToken: ResumeToken | undefined;

  constructor(private readonly io: Server) {}

  start(): void {
    const stream = OrderModel.collection.watch([], { fullDocument: 'updateLookup', resumeAfter: this.resumeToken });
    stream.on('change', (change) => {
      this.resumeToken = change._id;
      const doc = (change as { fullDocument?: { userId?: string; _id: { toString(): string } } }).fullDocument;
      if (!doc?.userId) return;
      this.io.to(`user:${doc.userId}`).emit('order:changed', { orderId: doc._id.toString(), changeType: change.operationType });
    });
    stream.on('error', (err) => {
      console.error('[change-stream] error', err);
      this.restart();
    });
    this.stream = stream;
  }

  private restart(): void {
    this.stream?.close().catch(() => {});
    setTimeout(() => this.start(), 1000);
  }

  async stop(): Promise<void> { await this.stream?.close(); this.stream = null; }
}

import type { Redis } from 'ioredis';

export interface TaskMessage { id: string; payload: string; }

export class StreamQueue {
  constructor(private readonly redis: Redis, private readonly streamKey: string, private readonly groupName: string) {}

  async ensureGroup(): Promise<void> {
    try { await this.redis.xgroup('CREATE', this.streamKey, this.groupName, '$', 'MKSTREAM'); }
    catch (e) { if (!String(e).includes('BUSYGROUP')) throw e; }
  }

  async enqueue(payload: string): Promise<string> {
    return this.redis.xadd(this.streamKey, '*', 'payload', payload) as Promise<string>;
  }

  async consume(consumerName: string, maxIdleMs: number, handler: (msg: TaskMessage) => Promise<void>): Promise<void> {
    while (true) {
      const reclaimed = await this.redis.xautoclaim(this.streamKey, this.groupName, consumerName, maxIdleMs, '0-0', 'COUNT', '10');
      const reclaimedMessages = (reclaimed as unknown as [string, Array<[string, string[]]>])[1];
      for (const [id, fields] of reclaimedMessages) await this.process(id, fields, handler);

      const res = (await this.redis.xreadgroup('GROUP', this.groupName, consumerName, 'COUNT', '10', 'BLOCK', '5000', 'STREAMS', this.streamKey, '>')) as Array<[string, Array<[string, string[]]>]> | null;
      if (!res) continue;
      for (const [, entries] of res) for (const [id, fields] of entries) await this.process(id, fields, handler);
    }
  }

  private async process(id: string, fields: string[], handler: (msg: TaskMessage) => Promise<void>): Promise<void> {
    const payloadIdx = fields.indexOf('payload');
    const payload = payloadIdx >= 0 ? fields[payloadIdx + 1] : '';
    try { await handler({ id, payload }); await this.redis.xack(this.streamKey, this.groupName, id); }
    catch (err) { console.error('[stream] handler failed', id, err); }
  }
}

export function assertNever(value: never, hint?: string): never {
  throw new Error(`Unhandled case${hint ? ` (${hint})` : ''}: ${JSON.stringify(value)}`);
}

export type Shape = { kind: 'circle'; radius: number } | { kind: 'square'; side: number } | { kind: 'triangle'; base: number; height: number };

export function area(shape: Shape): number {
  switch (shape.kind) {
    case 'circle': return Math.PI * shape.radius ** 2;
    case 'square': return shape.side ** 2;
    case 'triangle': return 0.5 * shape.base * shape.height;
    default: return assertNever(shape, 'area');
  }
}

export interface QueryBuilder<T, S extends keyof T> {
  where<K extends keyof T>(key: K, value: T[K]): QueryBuilder<T, S>;
  orderBy<K extends keyof T>(key: K, dir?: 'asc' | 'desc'): QueryBuilder<T, S>;
  select<K extends keyof T>(...keys: K[]): QueryBuilder<T, K>;
  exec(): Promise<Array<Pick<T, S>>>;
}

export function createBuilder<T>(executor: (spec: { where: Array<[keyof T, T[keyof T]]>; orderBy: Array<[keyof T, 'asc' | 'desc']>; select: ReadonlyArray<keyof T> | null }) => Promise<T[]>): QueryBuilder<T, keyof T> {
  function make<S extends keyof T>(state: { where: Array<[keyof T, T[keyof T]]>; orderBy: Array<[keyof T, 'asc' | 'desc']>; select: ReadonlyArray<keyof T> | null }): QueryBuilder<T, S> {
    return {
      where<K extends keyof T>(key: K, value: T[K]): QueryBuilder<T, S> {
        return make<S>({ ...state, where: [...state.where, [key, value as T[keyof T]]] });
      },
      orderBy<K extends keyof T>(key: K, dir: 'asc' | 'desc' = 'asc'): QueryBuilder<T, S> {
        return make<S>({ ...state, orderBy: [...state.orderBy, [key, dir]] });
      },
      select<K extends keyof T>(...keys: K[]): QueryBuilder<T, K> {
        return make<K>({ ...state, select: keys });
      },
      async exec(): Promise<Array<Pick<T, S>>> {
        const rows = await executor(state);
        if (!state.select) return rows as Array<Pick<T, S>>;
        return rows.map((row) => {
          const out: Partial<T> = {};
          for (const k of state.select!) out[k] = row[k];
          return out as Pick<T, S>;
        });
      },
    };
  }
  return make<keyof T>({ where: [], orderBy: [], select: null });
}

