import crypto from 'crypto';
import { Schema, model } from 'mongoose';

interface AuditEntry { _id: string; seq: number; ts: Date; actorId: string; action: string; targetId: string; metadata: Record<string, unknown>; prevHash: string; hash: string; }

const AuditSchema = new Schema<AuditEntry>({
  seq: { type: Number, required: true, unique: true },
  ts: { type: Date, default: Date.now },
  actorId: { type: String, required: true },
  action: { type: String, required: true },
  targetId: { type: String, required: true },
  metadata: { type: Schema.Types.Mixed, default: {} },
  prevHash: { type: String, required: true },
  hash: { type: String, required: true },
});

export const AuditModel = model<AuditEntry>('Audit', AuditSchema);

function computeHash(entry: Omit<AuditEntry, '_id' | 'hash'>): string {
  const canonical = JSON.stringify({ seq: entry.seq, ts: entry.ts.toISOString(), actorId: entry.actorId, action: entry.action, targetId: entry.targetId, metadata: entry.metadata, prevHash: entry.prevHash });
  return crypto.createHash('sha256').update(canonical).digest('hex');
}

export async function append(input: { actorId: string; action: string; targetId: string; metadata?: Record<string, unknown> }): Promise<AuditEntry> {
  const last = await AuditModel.findOne().sort({ seq: -1 }).lean<AuditEntry | null>();
  const seq = (last?.seq ?? 0) + 1;
  const prevHash = last?.hash ?? '0'.repeat(64);
  const baseEntry = { seq, ts: new Date(), actorId: input.actorId, action: input.action, targetId: input.targetId, metadata: input.metadata ?? {}, prevHash };
  const hash = computeHash(baseEntry);
  const created = await AuditModel.create({ ...baseEntry, hash });
  return created.toObject() as AuditEntry;
}

export async function verify(): Promise<{ valid: boolean; brokenAt?: number }> {
  const entries = await AuditModel.find().sort({ seq: 1 }).lean<AuditEntry[]>();
  let expectedPrev = '0'.repeat(64);
  for (const e of entries) {
    if (e.prevHash !== expectedPrev) return { valid: false, brokenAt: e.seq };
    const recomputed = computeHash({ seq: e.seq, ts: e.ts, actorId: e.actorId, action: e.action, targetId: e.targetId, metadata: e.metadata, prevHash: e.prevHash });
    if (recomputed !== e.hash) return { valid: false, brokenAt: e.seq };
    expectedPrev = e.hash;
  }
  return { valid: true };
}

