import { Request, Response, NextFunction, ErrorRequestHandler } from 'express';
import { AppError } from './errors';

interface Logger { warn(msg: string, ctx: Record<string, unknown>): void; error(msg: string, ctx: Record<string, unknown>): void; }

export function levelAwareErrorMiddleware(logger: Logger): ErrorRequestHandler {
  return (err: unknown, req: Request, res: Response, _next: NextFunction): void => {
    const isAppError = err instanceof AppError;
    const statusCode = isAppError ? err.statusCode : 500;
    const code = isAppError ? err.code : 'INTERNAL';
    const ctx = { method: req.method, path: req.path, statusCode, code };

    if (statusCode >= 500) {
      const e = err as Error;
      logger.error('server error', { ...ctx, message: e.message, stack: e.stack });
    } else {
      logger.warn('client error', { ...ctx, message: (err as Error).message });
    }

    if (res.headersSent) return;
    if (isAppError) res.status(statusCode).json({ error: { code, message: err.message, details: err.details } });
    else res.status(500).json({ error: { code, message: 'An unexpected error occurred' } });
  };
}

