import type { Redis } from 'ioredis';

export interface SwrOptions { freshTtlMs: number; staleTtlMs: number; refreshTimeoutMs: number; }

interface CacheEntry<T> { value: T; storedAt: number; }

export class SwrCache {
  private inflight = new Map<string, Promise<unknown>>();
  constructor(private readonly redis: Redis) {}

  async getOrFetch<T>(key: string, fetcher: () => Promise<T>, opts: SwrOptions): Promise<T> {
    const raw = await this.redis.get(key);
    const now = Date.now();
    if (raw) {
      const entry = JSON.parse(raw) as CacheEntry<T>;
      const age = now - entry.storedAt;
      if (age < opts.freshTtlMs) return entry.value;
      if (age < opts.staleTtlMs) {
        this.refresh(key, fetcher, opts).catch((e) => console.error('[swr] refresh failed', e));
        return entry.value;
      }
    }
    return this.refresh(key, fetcher, opts) as Promise<T>;
  }

  private refresh<T>(key: string, fetcher: () => Promise<T>, opts: SwrOptions): Promise<T> {
    const existing = this.inflight.get(key) as Promise<T> | undefined;
    if (existing) return existing;
    const p = (async () => {
      try {
        const value = await Promise.race([fetcher(), new Promise<T>((_, reject) => setTimeout(() => reject(new Error('REFRESH_TIMEOUT')), opts.refreshTimeoutMs))]);
        const entry: CacheEntry<T> = { value, storedAt: Date.now() };
        await this.redis.set(key, JSON.stringify(entry), 'PX', opts.staleTtlMs);
        return value;
      } finally { this.inflight.delete(key); }
    })();
    this.inflight.set(key, p);
    return p;
  }
}

type Required<S extends string> = Record<S, true>;

export class EmailBuilder<S extends string = never> {
  private state: { to?: string; from?: string; subject?: string; body?: string } = {};
  to(value: string): EmailBuilder<S | 'to'> { this.state.to = value; return this as unknown as EmailBuilder<S | 'to'>; }
  from(value: string): EmailBuilder<S | 'from'> { this.state.from = value; return this as unknown as EmailBuilder<S | 'from'>; }
  subject(value: string): EmailBuilder<S | 'subject'> { this.state.subject = value; return this as unknown as EmailBuilder<S | 'subject'>; }
  body(value: string): EmailBuilder<S | 'body'> { this.state.body = value; return this as unknown as EmailBuilder<S | 'body'>; }
  build(this: EmailBuilder<'to' | 'from' | 'subject'>): { to: string; from: string; subject: string; body: string } {
    return { to: this.state.to!, from: this.state.from!, subject: this.state.subject!, body: this.state.body ?? '' };
  }
}

export function newEmail(): EmailBuilder { return new EmailBuilder(); }

