import { Server } from 'socket.io';
import { createAdapter } from '@socket.io/mongo-adapter';
import { MongoClient } from 'mongodb';

const COLLECTION = 'socket.io-adapter-events';

export async function createMongoBackedIO(httpServer: import('http').Server, mongoUri: string, dbName: string): Promise<Server> {
  const client = new MongoClient(mongoUri);
  await client.connect();
  const db = client.db(dbName);
  try { await db.createCollection(COLLECTION, { capped: true, size: 100 * 1024 * 1024, max: 100_000 }); }
  catch (e) { if (!String(e).includes('already exists')) throw e; }

  const io = new Server(httpServer, { transports: ['websocket'], cors: { origin: process.env.CLIENT_ORIGIN, credentials: true } });
  io.adapter(createAdapter(db.collection(COLLECTION), { addCreatedAtField: true }));
  return io;
}

import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';

const SECRET = process.env.JWT_SECRET!;
const ACCESS_TTL_SEC = 15 * 60;
const SLIDE_THRESHOLD_SEC = 10 * 60;

function sign(userId: string): { token: string; exp: number } {
  const exp = Math.floor(Date.now() / 1000) + ACCESS_TTL_SEC;
  const token = jwt.sign({ sub: userId, exp }, SECRET, { algorithm: 'HS256' });
  return { token, exp };
}

export function slidingAuthMiddleware(req: Request, res: Response, next: NextFunction): void {
  const header = req.header('Authorization');
  const token = header?.startsWith('Bearer ') ? header.slice(7) : null;
  if (!token) { res.status(401).json({ error: 'NO_TOKEN' }); return; }
  let payload: { sub: string; exp: number };
  try { payload = jwt.verify(token, SECRET, { algorithms: ['HS256'] }) as typeof payload; }
  catch { res.status(401).json({ error: 'INVALID' }); return; }

  (req as Request & { userId: string }).userId = payload.sub;

  const secondsUntilExp = payload.exp - Math.floor(Date.now() / 1000);
  if (secondsUntilExp < ACCESS_TTL_SEC - SLIDE_THRESHOLD_SEC) {
    const refreshed = sign(payload.sub);
    res.setHeader('X-New-Access-Token', refreshed.token);
  }
  next();
}

import { useState, useCallback, FormEvent } from 'react';

type Errors<T> = Partial<Record<keyof T, string>>;
type Touched<T> = Partial<Record<keyof T, boolean>>;

export interface UseFormOptions<T> { initial: T; validate?: (values: T) => Errors<T>; onSubmit: (values: T) => Promise<void> | void; }

export function useForm<T extends Record<string, unknown>>({ initial, validate, onSubmit }: UseFormOptions<T>) {
  const [values, setValues] = useState<T>(initial);
  const [errors, setErrors] = useState<Errors<T>>({});
  const [touched, setTouched] = useState<Touched<T>>({});
  const [submitting, setSubmitting] = useState(false);

  const setField = useCallback(<K extends keyof T>(key: K, value: T[K]): void => {
    setValues((v) => ({ ...v, [key]: value }));
  }, []);

  const touchField = useCallback(<K extends keyof T>(key: K): void => {
    setTouched((t) => ({ ...t, [key]: true }));
  }, []);

  const handleSubmit = useCallback(async (e: FormEvent): Promise<void> => {
    e.preventDefault();
    const validation = validate ? validate(values) : ({} as Errors<T>);
    setErrors(validation);
    setTouched(Object.keys(values).reduce<Touched<T>>((acc, k) => ({ ...acc, [k as keyof T]: true }), {}));
    if (Object.keys(validation).length > 0) return;
    setSubmitting(true);
    try { await onSubmit(values); }
    finally { setSubmitting(false); }
  }, [values, validate, onSubmit]);

  const fieldProps = <K extends keyof T>(key: K) => ({
    value: values[key] as T[K],
    onChange: (e: React.ChangeEvent<HTMLInputElement>): void => setField(key, e.target.value as T[K]),
    onBlur: (): void => touchField(key),
    'aria-invalid': touched[key] && Boolean(errors[key]),
  });

  return { values, errors, touched, submitting, setField, handleSubmit, fieldProps };
}

import { Server } from 'socket.io';
import type { Redis } from 'ioredis';
import jwt from 'jsonwebtoken';

export function configureMiddleware(io: Server, redis: Redis, secret: string): void {
  io.use((socket, next) => {
    const token = (socket.handshake.auth as { token?: string }).token;
    if (!token) return next(new Error('UNAUTHENTICATED'));
    try {
      const decoded = jwt.verify(token, secret) as { sub: string };
      (socket.data as { userId: string }).userId = decoded.sub;
      next();
    } catch { next(new Error('INVALID_TOKEN')); }
  });

  io.use(async (socket, next) => {
    const userId = (socket.data as { userId: string }).userId;
    const key = `socket:rate:${userId}`;
    const count = await redis.incr(key);
    if (count === 1) await redis.expire(key, 60);
    if (count > 30) return next(new Error('TOO_MANY_CONNECTIONS'));
    next();
  });

  io.use((socket, next) => {
    const userId = (socket.data as { userId: string }).userId;
    console.log(JSON.stringify({ event: 'socket.connect_attempt', userId, ip: socket.handshake.address, ua: socket.handshake.headers['user-agent'] }));
    next();
  });
}

import { Request, Response, NextFunction } from 'express';
import crypto from 'crypto';
import type { Redis } from 'ioredis';

const TOLERANCE_SEC = 300;

export function replayProtection(redis: Redis, secret: string) {
  return async (req: Request, res: Response, next: NextFunction): Promise<void> => {
    const sig = req.header('X-Signature');
    const ts = req.header('X-Timestamp');
    const nonce = req.header('X-Nonce');
    if (!sig || !ts || !nonce) { res.status(400).json({ error: 'MISSING_HEADERS' }); return; }

    const tsNum = Number(ts);
    if (!Number.isFinite(tsNum) || Math.abs(Date.now() / 1000 - tsNum) > TOLERANCE_SEC) { res.status(400).json({ error: 'STALE' }); return; }

    const raw = (req.body as Buffer).toString('utf8');
    const expected = crypto.createHmac('sha256', secret).update(`${ts}.${nonce}.${raw}`).digest('hex');
    if (!crypto.timingSafeEqual(Buffer.from(expected, 'hex'), Buffer.from(sig, 'hex'))) { res.status(400).json({ error: 'BAD_SIG' }); return; }

    const nonceKey = `webhook-nonce:${nonce}`;
    const claimed = await redis.set(nonceKey, '1', 'EX', TOLERANCE_SEC, 'NX');
    if (claimed !== 'OK') { res.status(409).json({ error: 'REPLAY' }); return; }

    next();
  };
}

