interface StripeEventMap {
  'invoice.paid': { invoiceId: string; amountCents: number };
  'subscription.created': { subscriptionId: string; customerId: string };
  'charge.refunded': { chargeId: string; amountCents: number };
}

type Handler<K extends keyof StripeEventMap> = (data: StripeEventMap[K]) => Promise<void>;

export class StripeWebhookRouter {
  private handlers: { [K in keyof StripeEventMap]?: Handler<K> } = {};

  on<K extends keyof StripeEventMap>(event: K, handler: Handler<K>): this {
    this.handlers[event] = handler;
    return this;
  }

  async dispatch(event: { type: string; data: unknown }): Promise<{ handled: boolean }> {
    const handler = this.handlers[event.type as keyof StripeEventMap];
    if (!handler) return { handled: false };
    await (handler as (data: unknown) => Promise<void>)(event.data);
    return { handled: true };
  }
}

