import type { Redis } from 'ioredis';
import { Server, Socket } from 'socket.io';

export class StickyRoomManager {
  constructor(private readonly redis: Redis) {}

  private key(userId: string): string { return `sticky-rooms:${userId}`; }

  async join(socket: Socket, userId: string, roomId: string): Promise<void> {
    socket.join(roomId);
    await this.redis.sadd(this.key(userId), roomId);
  }

  async leave(socket: Socket, userId: string, roomId: string): Promise<void> {
    socket.leave(roomId);
    await this.redis.srem(this.key(userId), roomId);
  }

  async restoreOnConnect(socket: Socket, userId: string): Promise<void> {
    const rooms = await this.redis.smembers(this.key(userId));
    for (const room of rooms) socket.join(room);
  }

  async clearUser(userId: string): Promise<void> { await this.redis.del(this.key(userId)); }
}

export function attachSticky(io: Server, manager: StickyRoomManager): void {
  io.on('connection', async (socket) => {
    const userId = (socket.data as { userId?: string }).userId;
    if (!userId) return;
    await manager.restoreOnConnect(socket, userId);
  });
}

import { useEffect, useState } from 'react';
import type { Socket } from 'socket.io-client';

export interface StreamProgress<T> { state: 'idle' | 'streaming' | 'done' | 'error'; progress: number; data: T[]; error?: string; }

export function useStreamedQuery<T>(socket: Socket, queryEvent: string, params: unknown): StreamProgress<T> {
  const [state, setState] = useState<StreamProgress<T>>({ state: 'idle', progress: 0, data: [] });

  useEffect(() => {
    setState({ state: 'streaming', progress: 0, data: [] });
    const sessionId = crypto.randomUUID();
    const buffer: T[] = [];

    const onChunk = (msg: { sessionId: string; seq: number; totalSeq: number; items: T[] }): void => {
      if (msg.sessionId !== sessionId) return;
      buffer.push(...msg.items);
      setState({ state: 'streaming', progress: msg.totalSeq ? msg.seq / msg.totalSeq : 0, data: [...buffer] });
    };

    const onDone = (msg: { sessionId: string }): void => {
      if (msg.sessionId !== sessionId) return;
      setState((s) => ({ ...s, state: 'done', progress: 1 }));
    };

    const onError = (msg: { sessionId: string; error: string }): void => {
      if (msg.sessionId !== sessionId) return;
      setState((s) => ({ ...s, state: 'error', error: msg.error }));
    };

    socket.on(`${queryEvent}:chunk`, onChunk);
    socket.on(`${queryEvent}:done`, onDone);
    socket.on(`${queryEvent}:error`, onError);
    socket.emit(queryEvent, { sessionId, params });

    return () => {
      socket.off(`${queryEvent}:chunk`, onChunk);
      socket.off(`${queryEvent}:done`, onDone);
      socket.off(`${queryEvent}:error`, onError);
      socket.emit(`${queryEvent}:cancel`, { sessionId });
    };
  }, [socket, queryEvent, params]);

  return state;
}

import crypto from 'crypto';
import argon2 from 'argon2';
import { Schema, model, Types } from 'mongoose';

interface PasswordReset { userId: string; tokenHash: string; createdAt: Date; expiresAt: Date; usedAt: Date | null; }

const PasswordResetSchema = new Schema<PasswordReset>({
  userId: { type: String, required: true, index: true },
  tokenHash: { type: String, required: true },
  createdAt: { type: Date, default: Date.now },
  expiresAt: { type: Date, required: true, index: { expireAfterSeconds: 0 } },
  usedAt: { type: Date, default: null },
});

export const PasswordResetModel = model<PasswordReset>('PasswordReset', PasswordResetSchema);

const TTL_MS = 30 * 60 * 1000;

export async function createResetToken(userId: string): Promise<{ rawToken: string; resetId: string }> {
  const rawToken = crypto.randomBytes(32).toString('base64url');
  const tokenHash = await argon2.hash(rawToken, { type: argon2.argon2id });
  const doc = await PasswordResetModel.create({ userId, tokenHash, expiresAt: new Date(Date.now() + TTL_MS) });
  return { rawToken, resetId: doc._id.toString() };
}

export async function consumeResetToken(resetId: string, rawToken: string): Promise<{ userId: string } | null> {
  if (!Types.ObjectId.isValid(resetId)) return null;
  const doc = await PasswordResetModel.findById(resetId);
  if (!doc || doc.usedAt || doc.expiresAt.getTime() < Date.now()) return null;
  const valid = await argon2.verify(doc.tokenHash, rawToken);
  if (!valid) return null;
  doc.usedAt = new Date();
  await doc.save();
  return { userId: doc.userId };
}

import type { Redis } from 'ioredis';

export interface StuffingDetectorOptions { windowSec: number; distinctUsernameLimit: number; blockDurationSec: number; }

export class CredentialStuffingDetector {
  constructor(private readonly redis: Redis, private readonly opts: StuffingDetectorOptions) {}

  private userKey(ip: string): string { return `stuff:users:${ip}`; }
  private blockKey(ip: string): string { return `stuff:block:${ip}`; }

  async recordFailure(ip: string, username: string): Promise<void> {
    const userKey = this.userKey(ip);
    await this.redis.pfadd(userKey, username);
    await this.redis.expire(userKey, this.opts.windowSec);
    const distinct = await this.redis.pfcount(userKey);
    if (distinct >= this.opts.distinctUsernameLimit) {
      await this.redis.set(this.blockKey(ip), '1', 'EX', this.opts.blockDurationSec);
    }
  }

  async isBlocked(ip: string): Promise<boolean> { return (await this.redis.exists(this.blockKey(ip))) === 1; }

  async clearFailures(ip: string): Promise<void> { await this.redis.del(this.userKey(ip)); }
}

import { useCallback } from 'react';

interface ListProps<T> { items: ReadonlyArray<T>; selectedId: string | null; getId: (item: T) => string; renderItem: (item: T, isSelected: boolean) => React.ReactNode; }

export function ScrollIntoViewList<T>({ items, selectedId, getId, renderItem }: ListProps<T>): JSX.Element {
  const refCallback = useCallback((node: HTMLLIElement | null) => {
    if (!node) return;
    requestAnimationFrame(() => {
      node.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
    });
  }, []);

  return (
    <ul className="max-h-96 overflow-auto">
      {items.map((item) => {
        const id = getId(item);
        const isSelected = id === selectedId;
        return (
          <li key={id} ref={isSelected ? refCallback : undefined}>
            {renderItem(item, isSelected)}
          </li>
        );
      })}
    </ul>
  );
}

