export interface Specification<T> {
  isSatisfiedBy(item: T): boolean;
  and(other: Specification<T>): Specification<T>;
  or(other: Specification<T>): Specification<T>;
  not(): Specification<T>;
}

export abstract class BaseSpec<T> implements Specification<T> {
  abstract isSatisfiedBy(item: T): boolean;
  and(other: Specification<T>): Specification<T> { return new AndSpec(this, other); }
  or(other: Specification<T>): Specification<T> { return new OrSpec(this, other); }
  not(): Specification<T> { return new NotSpec(this); }
}

class AndSpec<T> extends BaseSpec<T> {
  constructor(private readonly a: Specification<T>, private readonly b: Specification<T>) { super(); }
  isSatisfiedBy(item: T): boolean { return this.a.isSatisfiedBy(item) && this.b.isSatisfiedBy(item); }
}
class OrSpec<T> extends BaseSpec<T> {
  constructor(private readonly a: Specification<T>, private readonly b: Specification<T>) { super(); }
  isSatisfiedBy(item: T): boolean { return this.a.isSatisfiedBy(item) || this.b.isSatisfiedBy(item); }
}
class NotSpec<T> extends BaseSpec<T> {
  constructor(private readonly s: Specification<T>) { super(); }
  isSatisfiedBy(item: T): boolean { return !this.s.isSatisfiedBy(item); }
}

export interface User { id: string; status: 'active' | 'suspended'; tier: 'free' | 'premium'; lastSeenAt: Date; }

export class IsActive extends BaseSpec<User> { isSatisfiedBy(u: User): boolean { return u.status === 'active'; } }
export class IsPremium extends BaseSpec<User> { isSatisfiedBy(u: User): boolean { return u.tier === 'premium'; } }
export class WasActiveWithin extends BaseSpec<User> {
  constructor(private readonly daysAgo: number) { super(); }
  isSatisfiedBy(u: User): boolean { return u.lastSeenAt.getTime() > Date.now() - this.daysAgo * 86400_000; }
}

