import { Server, Socket } from 'socket.io';

interface PrivateMessage { from: string; to: string; text: string; ts: number; }

export function mountPrivateChat(io: Server): void {
  io.on('connection', (socket: Socket) => {
    const userId = (socket.data as { userId?: string }).userId;
    if (!userId) { socket.disconnect(true); return; }
    socket.join(`user:${userId}`);

    socket.on('dm:send', (to: string, text: string, ack: (ok: boolean) => void) => {
      if (typeof to !== 'string' || typeof text !== 'string' || text.length === 0 || text.length > 2000) { ack(false); return; }
      const msg: PrivateMessage = { from: userId, to, text, ts: Date.now() };
      io.to(`user:${to}`).emit('dm:incoming', msg);
      socket.emit('dm:sent', msg);
      ack(true);
    });
  });
}

import crypto from 'crypto';
import argon2 from 'argon2';
import { Schema, model } from 'mongoose';

interface User { _id: string; email: string; emailVerified: boolean; verificationTokenHash: string | null; verificationExpiresAt: Date | null; lastVerificationSentAt: Date | null; }

const UserSchema = new Schema<User>({
  email: { type: String, required: true, unique: true },
  emailVerified: { type: Boolean, default: false },
  verificationTokenHash: String,
  verificationExpiresAt: Date,
  lastVerificationSentAt: Date,
});
export const UserModel = model<User>('User', UserSchema);

const TTL_MS = 24 * 3600 * 1000;
const RESEND_COOLDOWN_MS = 60 * 1000;

export async function startVerification(userId: string): Promise<{ rawToken: string } | { error: 'COOLDOWN' | 'NOT_FOUND' }> {
  const user = await UserModel.findById(userId);
  if (!user) return { error: 'NOT_FOUND' };
  if (user.lastVerificationSentAt && Date.now() - user.lastVerificationSentAt.getTime() < RESEND_COOLDOWN_MS) return { error: 'COOLDOWN' };
  const rawToken = crypto.randomBytes(32).toString('base64url');
  user.verificationTokenHash = await argon2.hash(rawToken);
  user.verificationExpiresAt = new Date(Date.now() + TTL_MS);
  user.lastVerificationSentAt = new Date();
  await user.save();
  return { rawToken };
}

export async function completeVerification(userId: string, rawToken: string): Promise<boolean> {
  const user = await UserModel.findById(userId);
  if (!user || !user.verificationTokenHash || !user.verificationExpiresAt) return false;
  if (user.verificationExpiresAt.getTime() < Date.now()) return false;
  const ok = await argon2.verify(user.verificationTokenHash, rawToken);
  if (!ok) return false;
  user.emailVerified = true;
  user.verificationTokenHash = null;
  user.verificationExpiresAt = null;
  await user.save();
  return true;
}

import { useRef, useState, ChangeEvent } from 'react';

function formatPhone(digits: string): string {
  const d = digits.slice(0, 10);
  if (d.length <= 3) return d;
  if (d.length <= 6) return `(${d.slice(0, 3)}) ${d.slice(3)}`;
  return `(${d.slice(0, 3)}) ${d.slice(3, 6)}-${d.slice(6)}`;
}

function countDigitsBefore(value: string, index: number): number {
  let count = 0;
  for (let i = 0; i < Math.min(index, value.length); i++) if (/\d/.test(value[i])) count++;
  return count;
}

function findCursorForDigitIndex(formatted: string, digitIndex: number): number {
  let seen = 0;
  for (let i = 0; i < formatted.length; i++) {
    if (seen >= digitIndex) return i;
    if (/\d/.test(formatted[i])) seen++;
  }
  return formatted.length;
}

export function PhoneInput(): JSX.Element {
  const [value, setValue] = useState('');
  const inputRef = useRef<HTMLInputElement>(null);

  const onChange = (e: ChangeEvent<HTMLInputElement>): void => {
    const rawCursor = e.target.selectionStart ?? e.target.value.length;
    const digitsBeforeCursor = countDigitsBefore(e.target.value, rawCursor);
    const onlyDigits = e.target.value.replace(/\D/g, '');
    const formatted = formatPhone(onlyDigits);
    setValue(formatted);
    requestAnimationFrame(() => {
      const newCursor = findCursorForDigitIndex(formatted, digitsBeforeCursor);
      inputRef.current?.setSelectionRange(newCursor, newCursor);
    });
  };

  return <input ref={inputRef} value={value} onChange={onChange} placeholder="(555) 123-4567" />;
}

export class InvariantError extends Error { constructor(msg: string) { super(msg); this.name = 'InvariantError'; } }

export interface OrderItem { sku: string; qty: number; unitPriceCents: number; }

export class Order {
  private constructor(
    public readonly id: string,
    public readonly userId: string,
    private items: OrderItem[],
    private status: 'draft' | 'placed' | 'paid' | 'cancelled',
  ) {}

  static create(id: string, userId: string): Order { return new Order(id, userId, [], 'draft'); }

  static rehydrate(snapshot: { id: string; userId: string; items: OrderItem[]; status: 'draft' | 'placed' | 'paid' | 'cancelled' }): Order {
    return new Order(snapshot.id, snapshot.userId, [...snapshot.items], snapshot.status);
  }

  addItem(item: OrderItem): void {
    if (this.status !== 'draft') throw new InvariantError('Cannot modify non-draft order');
    if (item.qty <= 0) throw new InvariantError('Quantity must be positive');
    if (item.unitPriceCents < 0) throw new InvariantError('Price cannot be negative');
    const existing = this.items.find((i) => i.sku === item.sku);
    if (existing) existing.qty += item.qty;
    else this.items.push({ ...item });
  }

  removeItem(sku: string): void {
    if (this.status !== 'draft') throw new InvariantError('Cannot modify non-draft order');
    this.items = this.items.filter((i) => i.sku !== sku);
  }

  place(): void {
    if (this.status !== 'draft') throw new InvariantError('Already placed');
    if (this.items.length === 0) throw new InvariantError('Cannot place empty order');
    this.status = 'placed';
  }

  markPaid(): void {
    if (this.status !== 'placed') throw new InvariantError('Order must be placed before paying');
    this.status = 'paid';
  }

  totalCents(): number { return this.items.reduce((sum, i) => sum + i.qty * i.unitPriceCents, 0); }

  toSnapshot(): { id: string; userId: string; items: OrderItem[]; status: 'draft' | 'placed' | 'paid' | 'cancelled'; totalCents: number } {
    return { id: this.id, userId: this.userId, items: [...this.items], status: this.status, totalCents: this.totalCents() };
  }
}

import { useEffect, useRef, useState, useCallback } from 'react';

export interface InfiniteScrollProps<T> { fetchPage: (page: number) => Promise<T[]>; renderItem: (item: T) => React.ReactNode; pageSize?: number; }

export function InfiniteScroll<T>({ fetchPage, renderItem }: InfiniteScrollProps<T>): JSX.Element {
  const [items, setItems] = useState<T[]>([]);
  const [page, setPage] = useState(0);
  const [loading, setLoading] = useState(false);
  const [done, setDone] = useState(false);
  const sentinelRef = useRef<HTMLDivElement>(null);

  const loadMore = useCallback(async () => {
    if (loading || done) return;
    setLoading(true);
    const next = await fetchPage(page);
    if (next.length === 0) setDone(true);
    else { setItems((prev) => [...prev, ...next]); setPage((p) => p + 1); }
    setLoading(false);
  }, [fetchPage, page, loading, done]);

  useEffect(() => {
    const node = sentinelRef.current;
    if (!node) return;
    const observer = new IntersectionObserver((entries) => {
      if (entries[0].isIntersecting) void loadMore();
    }, { rootMargin: '500px' });
    observer.observe(node);
    return () => observer.disconnect();
  }, [loadMore]);

  return (
    <div>
      <ul>{items.map((item, i) => <li key={i}>{renderItem(item)}</li>)}</ul>
      {!done && <div ref={sentinelRef} className="py-8 text-center text-gray-500">{loading ? 'Loading…' : 'Scroll for more'}</div>}
    </div>
  );
}

import { Model, Error as MongooseError } from 'mongoose';

export async function upsertByUnique<T>(model: Model<T>, filter: Record<string, unknown>, set: Record<string, unknown>, setOnInsert: Record<string, unknown> = {}): Promise<T> {
  for (let attempt = 0; attempt < 2; attempt++) {
    try {
      const doc = await model.findOneAndUpdate(
        filter,
        { $set: set, $setOnInsert: setOnInsert },
        { new: true, upsert: true, lean: true, runValidators: true },
      );
      return doc as T;
    } catch (err) {
      const isDup = (err as { code?: number }).code === 11000 || err instanceof MongooseError.MongooseError;
      if (isDup && attempt === 0) continue;
      throw err;
    }
  }
  throw new Error('UPSERT_FAILED');
}

export interface Cat { kind: 'cat'; lives: number; }
export interface Dog { kind: 'dog'; loyalty: number; }
export type Pet = Cat | Dog;

export function isPet(value: unknown): value is Pet {
  if (!value || typeof value !== 'object') return false;
  const v = value as { kind?: unknown };
  if (v.kind === 'cat') {
    const c = v as { kind: 'cat'; lives?: unknown };
    return typeof c.lives === 'number' && Number.isFinite(c.lives);
  }
  if (v.kind === 'dog') {
    const d = v as { kind: 'dog'; loyalty?: unknown };
    return typeof d.loyalty === 'number' && Number.isFinite(d.loyalty);
  }
  return false;
}

export function isArrayOf<T>(value: unknown, itemGuard: (x: unknown) => x is T): value is T[] {
  return Array.isArray(value) && value.every(itemGuard);
}

