import crypto from 'crypto';
import { Request, Response, NextFunction } from 'express';

export function apiKeyMiddleware(expectedKey: string) {
  const expectedBuf = Buffer.from(expectedKey);
  return (req: Request, res: Response, next: NextFunction): void => {
    const provided = req.header('X-Api-Key');
    if (!provided) { res.status(401).json({ error: 'NO_KEY' }); return; }
    const providedBuf = Buffer.from(provided);
    if (providedBuf.length !== expectedBuf.length) { res.status(401).json({ error: 'INVALID' }); return; }
    if (!crypto.timingSafeEqual(providedBuf, expectedBuf)) { res.status(401).json({ error: 'INVALID' }); return; }
    next();
  };
}

