interface ErrorReporter { report(error: Error, context: Record<string, unknown>): void; }

export function useAsyncReporter(reporter: ErrorReporter): { runSafely<T>(fn: () => Promise<T>, context?: Record<string, unknown>): Promise<T | null>; error: Error | null; clear: () => void } {
  const [error, setError] = useState<Error | null>(null);

  const runSafely = async <T,>(fn: () => Promise<T>, context: Record<string, unknown> = {}): Promise<T | null> => {
    try { return await fn(); }
    catch (e) {
      const err = e instanceof Error ? e : new Error(String(e));
      reporter.report(err, context);
      setError(err);
      return null;
    }
  };

  return { runSafely, error, clear: () => setError(null) };
}

