export interface UserDto { id: string; name: string; email: string; }
export interface UserReadService { findById(id: string): Promise<UserDto | null>; }

export class DbUserReadService implements UserReadService {
  async findById(id: string): Promise<UserDto | null> { return { id, name: 'Demo', email: 'a@b.co' }; }
}

export class CachedUserReadService implements UserReadService {
  private cache = new Map<string, { value: UserDto | null; expiresAt: number }>();
  constructor(private readonly inner: UserReadService, private readonly ttlMs: number) {}

  async findById(id: string): Promise<UserDto | null> {
    const entry = this.cache.get(id);
    if (entry && entry.expiresAt > Date.now()) return entry.value;
    const fresh = await this.inner.findById(id);
    this.cache.set(id, { value: fresh, expiresAt: Date.now() + this.ttlMs });
    return fresh;
  }

  invalidate(id: string): void { this.cache.delete(id); }
}

export class LoggingUserReadService implements UserReadService {
  constructor(private readonly inner: UserReadService, private readonly log: (msg: string, ctx: Record<string, unknown>) => void) {}
  async findById(id: string): Promise<UserDto | null> {
    const start = Date.now();
    const result = await this.inner.findById(id);
    this.log('user.findById', { id, hit: result !== null, durationMs: Date.now() - start });
    return result;
  }
}

