import compression from 'compression';
import { Request, Response } from 'express';

export function compressionMiddleware() {
  return compression({
    threshold: 1024,
    level: 6,
    filter: (req: Request, res: Response): boolean => {
      if (req.headers['x-no-compression']) return false;
      const contentType = res.getHeader('content-type');
      const ct = typeof contentType === 'string' ? contentType.toLowerCase() : '';
      if (ct.startsWith('image/') || ct.startsWith('video/') || ct.startsWith('audio/')) return false;
      if (ct.startsWith('text/event-stream')) return false;
      return compression.filter(req, res);
    },
  });
}

import { Pool, PoolClient } from 'pg';
import crypto from 'crypto';

function lockId(name: string): bigint {
  const hash = crypto.createHash('sha256').update(name).digest();
  return hash.readBigInt64BE(0);
}

export interface AdvisoryLock { release(): Promise<void>; client: PoolClient; }

export async function tryAcquireAdvisoryLock(pool: Pool, name: string): Promise<AdvisoryLock | null> {
  const client = await pool.connect();
  try {
    const result = await client.query<{ pg_try_advisory_lock: boolean }>('SELECT pg_try_advisory_lock($1) AS pg_try_advisory_lock', [lockId(name).toString()]);
    if (!result.rows[0].pg_try_advisory_lock) { client.release(); return null; }
    return {
      client,
      release: async () => {
        try { await client.query('SELECT pg_advisory_unlock($1)', [lockId(name).toString()]); }
        finally { client.release(); }
      },
    };
  } catch (err) { client.release(); throw err; }
}

export async function withCron(pool: Pool, name: string, work: () => Promise<void>): Promise<boolean> {
  const lock = await tryAcquireAdvisoryLock(pool, name);
  if (!lock) return false;
  try { await work(); return true; }
  finally { await lock.release(); }
}

