import { Registry, Counter, Gauge, collectDefaultMetrics } from 'prom-client';
import { Server, Socket } from 'socket.io';
import { Request, Response } from 'express';

export class IoPromMetrics {
  readonly registry = new Registry();
  private readonly connections: Gauge<string>;
  private readonly events: Counter<'event'>;
  private readonly disconnects: Counter<'reason'>;

  constructor(prefix = 'socketio_') {
    collectDefaultMetrics({ register: this.registry, prefix });
    this.connections = new Gauge({ name: `${prefix}connections`, help: 'Current open Socket.IO connections', registers: [this.registry] });
    this.events = new Counter({ name: `${prefix}events_total`, help: 'Total Socket.IO events received', labelNames: ['event'], registers: [this.registry] });
    this.disconnects = new Counter({ name: `${prefix}disconnects_total`, help: 'Total disconnects by reason', labelNames: ['reason'], registers: [this.registry] });
  }

  attach(io: Server): void {
    setInterval(() => this.connections.set(io.engine.clientsCount), 10_000);
    io.on('connection', (socket: Socket) => {
      socket.onAny((event) => this.events.inc({ event: String(event).slice(0, 50) }));
      socket.on('disconnect', (reason) => this.disconnects.inc({ reason }));
    });
  }

  handler(req: Request, res: Response): void {
    void this.registry.metrics().then((m) => res.setHeader('Content-Type', this.registry.contentType).send(m));
  }
}

