export function SafeMarkdown({ source }: { source: string }): JSX.Element {
  const html = useMemo(() => {
    const raw = marked.parse(source, { async: false, breaks: true, gfm: true }) as string;
    const cleaned = DOMPurify.sanitize(raw, PURIFY_CONFIG);
