  return <div className="prose" dangerouslySetInnerHTML={{ __html: html }} />;
}

import { useReducer, useMemo, Reducer } from 'react';

export type Middleware<S, A> = (api: { getState: () => S; dispatch: (action: A) => void }) => (next: (action: A) => void) => (action: A) => void;

export function useReducerWithMiddleware<S, A>(reducer: Reducer<S, A>, initial: S, middlewares: ReadonlyArray<Middleware<S, A>>): [S, (action: A) => void] {
  const [state, baseDispatch] = useReducer(reducer, initial);
  const stateRef = { current: state };
  stateRef.current = state;

  const dispatch = useMemo(() => {
    const api = { getState: () => stateRef.current, dispatch: (a: A) => composedDispatch(a) };
    const chain = middlewares.map((m) => m(api));
    const composedDispatch = chain.reduceRight<(action: A) => void>((acc, mw) => mw(acc), baseDispatch);
    return composedDispatch;
  }, [middlewares]);

  return [state, dispatch];
}

export const loggerMiddleware = <S, A>(): Middleware<S, A> => (api) => (next) => (action) => {
  console.log('[action]', action, 'prevState', api.getState());
  next(action);
};

export const persistMiddleware = <S, A>(key: string): Middleware<S, A> => (api) => (next) => (action) => {
  next(action);
  try { localStorage.setItem(key, JSON.stringify(api.getState())); }
  catch { /* quota or disabled */ }
};

import express from 'express';
