export function configureSpa(app: express.Express, apiRouter: express.Router, distDir: string): void {
  app.use('/api', apiRouter);
  app.use('/api/*', (_req, _res, next) => next(new NotFoundError('Route not found')));
  app.use(express.static(distDir, { maxAge: '1y', immutable: true, etag: true, index: false }));
  app.get('*', (req: express.Request, res: express.Response, next: express.NextFunction) => {
