import { Queue, Worker, Job, QueueEvents } from 'bullmq';
import type { Redis } from 'ioredis';

export interface SendEmailJob { to: string; subject: string; body: string; }

class PermanentError extends Error { constructor(msg: string) { super(msg); this.name = 'PermanentError'; } }

export function createEmailQueue(connection: Redis): { queue: Queue<SendEmailJob>; worker: Worker<SendEmailJob>; events: QueueEvents } {
  const queue = new Queue<SendEmailJob>('email', { connection, defaultJobOptions: { attempts: 5, backoff: { type: 'exponential', delay: 2000 }, removeOnComplete: 100, removeOnFail: 500 } });
  const dlq = new Queue<SendEmailJob & { lastError: string }>('email-dead', { connection });
  const events = new QueueEvents('email', { connection });

  const worker = new Worker<SendEmailJob>('email', async (job: Job<SendEmailJob>) => {
    try { return await sendEmail(job.data); }
    catch (err) {
      if (err instanceof PermanentError) {
        await dlq.add('permanent', { ...job.data, lastError: err.message });
        return;
      }
      throw err;
    }
  }, { connection });

  worker.on('failed', async (job, err) => {
    if (job && job.attemptsMade >= (job.opts.attempts ?? 0)) {
      await dlq.add('exhausted', { ...job.data, lastError: err.message });
    }
  });

  return { queue, worker, events };
}

async function sendEmail(_data: SendEmailJob): Promise<{ messageId: string }> {
  return { messageId: 'm1' };
}

export type Path<T> = T extends object
  ? { [K in keyof T & (string | number)]: T[K] extends object ? `${K}` | `${K}.${Path<T[K]>}` : `${K}` }[keyof T & (string | number)]
  : never;

export type ValueAtPath<T, P extends string> =
  P extends `${infer Head}.${infer Rest}`
    ? Head extends keyof T ? ValueAtPath<T[Head], Rest> : never
    : P extends keyof T ? T[P] : never;

export function getPath<T, P extends Path<T>>(obj: T, path: P): ValueAtPath<T, P> {
  const parts = (path as string).split('.');
  let current: unknown = obj;
  for (const part of parts) {
    if (current === null || current === undefined || typeof current !== 'object') return undefined as ValueAtPath<T, P>;
    current = (current as Record<string, unknown>)[part];
  }
  return current as ValueAtPath<T, P>;
}

