import { Request, Response, NextFunction } from 'express';
import crypto from 'crypto';

interface Logger { warn(msg: string, ctx: Record<string, unknown>): void; }

export function strictCspMiddleware(opts: { reportOnly: boolean; reportEndpoint: string }) {
  return (req: Request, res: Response, next: NextFunction): void => {
    const nonce = crypto.randomBytes(16).toString('base64');
    (res.locals as { cspNonce: string }).cspNonce = nonce;
    const policy = [
      `default-src 'self'`,
      `script-src 'self' 'nonce-${nonce}' 'strict-dynamic' https:`,
      `style-src 'self' 'nonce-${nonce}'`,
      `img-src 'self' data: https:`,
      `font-src 'self'`,
      `connect-src 'self' wss://api.example.com`,
      `object-src 'none'`,
      `base-uri 'self'`,
      `frame-ancestors 'none'`,
      `require-trusted-types-for 'script'`,
      `report-uri ${opts.reportEndpoint}`,
    ].join('; ');
    res.setHeader(opts.reportOnly ? 'Content-Security-Policy-Report-Only' : 'Content-Security-Policy', policy);
    next();
  };
}

export function cspReportHandler(logger: Logger) {
  return (req: Request, res: Response): void => {
    const report = req.body as { 'csp-report'?: Record<string, unknown> };
    if (report && report['csp-report']) logger.warn('csp.violation', report['csp-report']);
    res.status(204).end();
  };
}

import { useState, useRef, useCallback } from 'react';

export interface UseAsyncCallback<A extends unknown[], R> { call: (...args: A) => Promise<R | null>; loading: boolean; error: Error | null; }

export function useAsyncCallback<A extends unknown[], R>(fn: (...args: A) => Promise<R>): UseAsyncCallback<A, R> {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<Error | null>(null);
  const generationRef = useRef(0);

  const call = useCallback(async (...args: A): Promise<R | null> => {
    const gen = ++generationRef.current;
    setLoading(true);
    setError(null);
    try {
      const result = await fn(...args);
      if (gen !== generationRef.current) return null;
      setLoading(false);
      return result;
    } catch (e) {
      if (gen !== generationRef.current) return null;
      const err = e instanceof Error ? e : new Error(String(e));
      setError(err);
      setLoading(false);
      return null;
    }
  }, [fn]);

  return { call, loading, error };
}

import { Request, Response, NextFunction, RequestHandler } from 'express';

declare module 'express-serve-static-core' { interface Request { abortSignal?: AbortSignal; } }

export function withTimeout(ms: number, handler: RequestHandler): RequestHandler {
  return async (req: Request, res: Response, next: NextFunction) => {
    const controller = new AbortController();
    req.abortSignal = controller.signal;
    let timedOut = false;
    const timer = setTimeout(() => {
      timedOut = true;
      controller.abort();
      if (!res.headersSent) res.status(504).json({ error: 'TIMEOUT' });
    }, ms);

    res.on('finish', () => clearTimeout(timer));
    res.on('close', () => clearTimeout(timer));

    try { await Promise.resolve(handler(req, res, next)); }
    catch (err) { if (!timedOut) next(err); }
    finally { clearTimeout(timer); }
  };
}

