import { Request, Response } from 'express';
import type { Server } from 'socket.io';
import type { Redis } from 'ioredis';

export function healthHandlers(io: Server, redis: Redis) {
  return {
    liveness: (_req: Request, res: Response): void => { res.json({ ok: true, uptime: process.uptime() }); },
    readiness: async (_req: Request, res: Response): Promise<void> => {
      const checks: Record<string, { ok: boolean; latencyMs?: number; error?: string }> = {};
      const t0 = Date.now();
      try { await redis.ping(); checks.redis = { ok: true, latencyMs: Date.now() - t0 }; }
      catch (e) { checks.redis = { ok: false, error: (e as Error).message }; }
      checks.socketio = { ok: io.engine.clientsCount >= 0 };
      const allOk = Object.values(checks).every((c) => c.ok);
      res.status(allOk ? 200 : 503).json({ ok: allOk, checks, connections: io.engine.clientsCount });
    },
  };
}

import crypto from 'crypto';

export interface EncryptedValue { v: 1; iv: string; ct: string; tag: string; }

export class FieldCipher {
  constructor(private readonly key: Buffer) { if (key.length !== 32) throw new Error('KEY_LENGTH_32'); }

  static fromBase64(base64Key: string): FieldCipher { return new FieldCipher(Buffer.from(base64Key, 'base64')); }

  encrypt(plaintext: string): EncryptedValue {
    const iv = crypto.randomBytes(12);
    const cipher = crypto.createCipheriv('aes-256-gcm', this.key, iv);
    const ct = Buffer.concat([cipher.update(plaintext, 'utf8'), cipher.final()]);
    return { v: 1, iv: iv.toString('base64'), ct: ct.toString('base64'), tag: cipher.getAuthTag().toString('base64') };
  }

  decrypt(value: EncryptedValue): string {
    if (value.v !== 1) throw new Error('UNKNOWN_VERSION');
    const iv = Buffer.from(value.iv, 'base64');
    const ct = Buffer.from(value.ct, 'base64');
    const tag = Buffer.from(value.tag, 'base64');
    const decipher = crypto.createDecipheriv('aes-256-gcm', this.key, iv);
    decipher.setAuthTag(tag);
    const plain = Buffer.concat([decipher.update(ct), decipher.final()]);
    return plain.toString('utf8');
  }
}

export type OptionalKeys<T> = { [K in keyof T]-?: {} extends Pick<T, K> ? K : never }[keyof T];
export type RequiredKeys<T> = { [K in keyof T]-?: {} extends Pick<T, K> ? never : K }[keyof T];

export function withDefaults<T extends object>(input: Partial<T>, defaults: Required<Pick<T, OptionalKeys<T>>>): T {
  return { ...defaults, ...input } as T;
}

export interface Config { host: string; port: number; tls?: boolean; timeout?: number; }

export function buildConfig(input: Partial<Config> & Pick<Config, RequiredKeys<Config>>): Config {
  return withDefaults(input, { tls: true, timeout: 30_000 });
}

import { Socket } from 'socket.io';

interface Bucket { tokens: number; lastRefillMs: number; }

export class TokenBucket {
  private buckets = new Map<string, Bucket>();
  constructor(private readonly capacity: number, private readonly refillPerSec: number) {}

  tryConsume(key: string): boolean {
    const now = Date.now();
    let bucket = this.buckets.get(key);
    if (!bucket) { bucket = { tokens: this.capacity, lastRefillMs: now }; this.buckets.set(key, bucket); }
    const elapsedMs = now - bucket.lastRefillMs;
    bucket.tokens = Math.min(this.capacity, bucket.tokens + (elapsedMs / 1000) * this.refillPerSec);
    bucket.lastRefillMs = now;
    if (bucket.tokens < 1) return false;
    bucket.tokens -= 1;
    return true;
  }
}

export function attachTypingThrottle(socket: Socket, bucket: TokenBucket): void {
  const userId = (socket.data as { userId: string }).userId;
  socket.on('typing', (roomId: string) => {
    if (!bucket.tryConsume(userId)) return;
    socket.to(roomId).emit('peer-typing', { userId });
  });
}

export function shallowEqual<T>(a: T, b: T): boolean {
  if (Object.is(a, b)) return true;
  if (typeof a !== 'object' || a === null || typeof b !== 'object' || b === null) return false;
  if (Array.isArray(a) && Array.isArray(b)) {
    if (a.length !== b.length) return false;
    for (let i = 0; i < a.length; i++) if (!Object.is(a[i], b[i])) return false;
    return true;
  }
  const aKeys = Object.keys(a as object);
  const bKeys = Object.keys(b as object);
  if (aKeys.length !== bKeys.length) return false;
  for (const k of aKeys) if (!Object.is((a as Record<string, unknown>)[k], (b as Record<string, unknown>)[k])) return false;
  return true;
}

