import { useState, useDeferredValue, useMemo } from 'react';

interface Item { id: string; name: string; }

export function DeferredSearchList({ items }: { items: ReadonlyArray<Item> }): JSX.Element {
  const [query, setQuery] = useState('');
  const deferredQuery = useDeferredValue(query);
  const isStale = query !== deferredQuery;

  const filtered = useMemo(() => {
    const needle = deferredQuery.trim().toLowerCase();
    return needle ? items.filter((i) => i.name.toLowerCase().includes(needle)) : items;
  }, [items, deferredQuery]);

  return (
    <div>
      <input value={query} onChange={(e) => setQuery(e.target.value)} placeholder="Search" />
      <ul style={{ opacity: isStale ? 0.6 : 1 }}>
        {filtered.slice(0, 200).map((i) => <li key={i.id}>{i.name}</li>)}
      </ul>
    </div>
  );
}

interface NotificationChannel { name: string; send(text: string): Promise<{ messageId: string }>; }

export async function broadcastAndCollect(channels: ReadonlyArray<NotificationChannel>, text: string): Promise<{ delivered: string[]; failed: Array<{ channel: string; error: string }> }> {
  const results = await Promise.allSettled(channels.map(async (c) => ({ channel: c.name, ...(await c.send(text)) })));
  const delivered: string[] = [];
  const failed: Array<{ channel: string; error: string }> = [];
  for (const r of results) {
    if (r.status === 'fulfilled') delivered.push(r.value.channel);
    else failed.push({ channel: 'unknown', error: r.reason instanceof Error ? r.reason.message : String(r.reason) });
  }
  return { delivered, failed };
}

export async function validateBatch(inputs: ReadonlyArray<{ id: string; value: string }>): Promise<void> {
  await Promise.all(inputs.map(async (i) => {
    if (i.value.length === 0) throw new Error(`EMPTY:${i.id}`);
  }));
}

