import { Request, Response, NextFunction } from 'express';

export interface CaptchaVerifier { verify(token: string, ip: string): Promise<{ success: boolean; score?: number }>; }

export class TurnstileVerifier implements CaptchaVerifier {
  constructor(private readonly secret: string) {}
  async verify(token: string, ip: string): Promise<{ success: boolean; score?: number }> {
    const body = new URLSearchParams({ secret: this.secret, response: token, remoteip: ip });
    const res = await fetch('https://challenges.cloudflare.com/turnstile/v0/siteverify', { method: 'POST', body });
    if (!res.ok) return { success: false };
    const data = await res.json() as { success: boolean; score?: number };
    return data;
  }
}

export function captchaMiddleware(verifier: CaptchaVerifier) {
  return async (req: Request, res: Response, next: NextFunction): Promise<void> => {
    const token = req.header('X-Captcha-Token');
    if (!token) { res.status(400).json({ error: 'CAPTCHA_REQUIRED' }); return; }
    const result = await verifier.verify(token, req.ip ?? '');
    if (!result.success) { res.status(403).json({ error: 'CAPTCHA_FAILED' }); return; }
    next();
  };
}
